<script setup>
defineProps({
  role: { type: String, required: true, validator: v => ['user', 'agent', 'system'].includes(v) },
  content: { type: String, required: true },
  timestamp: { type: String, default: '' },
  status: { type: String, default: '' },  // sending / sent / read / failed
})
</script>

<template>
  <div
    class="flex w-full mb-3"
    :class="role === 'user' ? 'justify-end' : 'justify-start'"
    :data-testid="`bubble-${role}`"
  >
    <div
      class="max-w-[75%] px-4 py-2.5 rounded-2xl text-sm leading-relaxed break-words"
      :class="{
        'bg-akong-bubble-user text-white rounded-br-sm': role === 'user',
        'bg-akong-bubble-agent text-akong-ink rounded-bl-sm': role === 'agent',
        'bg-transparent text-akong-muted text-xs italic mx-auto': role === 'system',
      }"
    >
      <slot>{{ content }}</slot>
      <div v-if="timestamp || status" class="mt-1 flex items-center gap-1.5 text-[10px] opacity-60">
        <span v-if="timestamp">{{ timestamp }}</span>
        <span v-if="status === 'sending'">· 发送中</span>
        <span v-if="status === 'failed'">· 失败</span>
        <span v-if="status === 'read'">· 已读</span>
      </div>
    </div>
  </div>
</template>
